import React, { useEffect, useRef } from 'react';
import styled from 'styled-components';
import { srConfig, email } from '@config';
import sr from '@utils/sr';
import { usePrefersReducedMotion } from '@hooks';

const StyledContactSection = styled.section`
  max-width: 600px;
  margin: 0 auto 100px;
  text-align: center;

  @media (max-width: 768px) {
    margin: 0 auto 50px;
  }

  .overline {
    display: block;
    margin-bottom: 20px;
    color: var(--green);
    font-family: var(--font-mono);
    font-size: var(--fz-md);
    font-weight: 400;

    &:before {
      bottom: 0;
      font-size: var(--fz-sm);
    }

    &:after {
      display: none;
    }
  }

  .title {
    font-size: clamp(40px, 5vw, 60px);
  }

  .email-link {
    ${({ theme }) => theme.mixins.bigButton};
    margin-top: 50px;
  }
`;

const Contact = () => {
  const revealContainer = useRef(null);
  const prefersReducedMotion = usePrefersReducedMotion();

  useEffect(() => {
    if (prefersReducedMotion) {
      return;
    }

    sr.reveal(revealContainer.current, srConfig());
  }, []);

  return (
    <StyledContactSection id="contact" ref={revealContainer}>
      <h2 className="numbered-heading overline">What’s Next?</h2>

      <h2 className="title">Get In Touch</h2>

      <p>
        I'm building an early-stage startup using AI to accelerate drug discovery for inflammatory bowel disease (IBD), lupus, and metabolic disorders. I'm looking for co-founders and collaborators who share the mission.
      </p>
      <p>
        I also built <a href="https://duitapp.ai" target="_blank" rel="noreferrer">Duit</a>, an AI-powered research feed that helps researchers stay current with the latest publications. Whether you want to try it, join the team, or just chat about science, my inbox is always open.
      </p>

      <a className="email-link" href={`mailto:${email}`}>
        Say Hello!
      </a>
    </StyledContactSection>
  );
};

export default Contact;
